/**
 * A constraint on the values that are going to be deleted.
 */
export interface DeletionConstraint {
    /**
     * A custom message for invalid values.
     */
    customMessage?: string;
    /**
     * The ID of a custom validator.
     */
    customValidatorId?: string;
    schemaIds?: string[];
    /**
     * The maximum time in seconds the custom validator is allowed to run.
     */
    timeout?: number;
    /**
     * The type of the deletion constraint.
     */
    type: 'CUSTOM_VALIDATOR_REF' | 'REFERENTIAL_INTEGRITY' | 'UNKNOWN';
}
